const VECTORS_B64 = "";

// ─── DÉCODAGE VECTEURS (float32 LE, normalisés à l'indexation) ──
function decodeVectors(b64) {
  // atob disponible en Node 16+
  const bin = atob(b64);
  const buf = new ArrayBuffer(bin.length);
  const u8 = new Uint8Array(buf);
  for (let i = 0; i < bin.length; i++) u8[i] = bin.charCodeAt(i);
  return new Float32Array(buf);
}
let ALL_VECS;
try { ALL_VECS = decodeVectors(VECTORS_B64); }
catch (e) { ALL_VECS = new Float32Array(0); }

// Normaliser les vecteurs d'index (en place) pour que cosine = produit scalaire
if (ALL_VECS.length === N * DIM) {
  for (let i = 0; i < N; i++) {
    const off = i * DIM;
    let s = 0;
    for (let j = 0; j < DIM; j++) s += ALL_VECS[off + j] * ALL_VECS[off + j];
    const inv = s > 0 ? 1 / Math.sqrt(s) : 0;
    if (inv !== 1) for (let j = 0; j < DIM; j++) ALL_VECS[off + j] *= inv;
  }
}

// ─── NORMALISATION FR ────────────────────────────────────
function unaccent(s) {
  return s.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}
const STOPWORDS_FR = new Set([
  'le','la','les','un','une','des','de','du','au','aux','en','et','ou','mais','donc','car',
  'est','sont','ete','etre','avoir','avec','sans','sur','sous','dans','pour','par','que','qui',
  'quoi','dont','ce','ces','cet','cette','se','sa','son','ses','leur','leurs','on','il','elle',
  'ils','elles','nous','vous','je','tu','moi','toi','lui','eux','mon','ma','mes','ton','ta','tes',
  'plus','moins','tres','bien','aussi','alors','puis','quand','comme','chez','entre','vers','dès',
  'depuis','apres','avant','pendant','jusqu','si','non','oui','pas','ni','ne','y','a','o'
]);
function tokenize(s) {
  return unaccent(String(s).toLowerCase())
    .replace(/[^a-z0-9\s]/g, ' ')
    .split(/\s+/)
    .filter(t => t.length >= 2 && !STOPWORDS_FR.has(t));
}
// Stemming léger FR (Porter simplifié adapté)
function lightStem(t) {
  // Codes NGAP (ami14, amx4, ais3, bsa, bsb, bsc, ifd, ifi, ik, mci, mie...) : ne pas stemmer
  if (/^[a-z]{2,3}\d/.test(t) || /^(bs[abc]|ais|ami|amx|ifd|ifi|ik|mci|mie|mau|tls|tld|tll|dim|nuit)$/.test(t)) return t;
  // Suppression suffixes courants
  return t
    .replace(/(ations|ateurs|atrices|ements|emments|issements)$/,'')
    .replace(/(ation|ateur|atrice|ement|emment|issement|issant|issants|aison|aisons)$/,'')
    .replace(/(euse|euses|eur|eurs|eux|ive|ives|if|ifs)$/,'')
    .replace(/(ement|ments|ment)$/,'')
    .replace(/(aient|erent|aient|asses|asses|ent|ons|ez|es|e|s)$/,'')
    .replace(/(ance|ances|ence|ences|ique|iques)$/,'')
    ;
}

// ─── EXPANSION SYNONYMES NGAP ────────────────────────────
const SYNONYMS = {
  // Cliniques ↔ codes NGAP
