  'escarre':    ['plaie','ulcere','pansement','necrose','ami4','mci'],
  'plaie':      ['pansement','escarre','ulcere','necrose','ami4'],
  // Injection
  'injection':  ['piqure','insuline','anticoagulant','heparine','lovenox','ami','amx'],
