  // Majorations
  'nuit':       ['nocturne','isn'],
  'dimanche':   ['ferie','feries','isd'],
  'enfant':     ['bebe','nourrisson','mie','pediatrique'],
  // Post-op
  'postop':     ['postoperatoire','chirurgie','redon','drain','ami39','ami42'],
  'drain':      ['redon','ami28','postop'],
  // Distance / déplacement
  'kilometre':  ['km','ik','deplacement','distance'],
  'distance':   ['km','kilometre','ik'],
  'domicile':   ['ifd','ifi','deplacement'],
  // BPCO / IC
  'bpco':       ['bronchopneumopathie','ic','insuffisance','cardiaque','ami58'],
  // Codes NGAP → labels cliniques (pour que BM25 match même si seul le code est dans la query)
  'ami14':      ['perfusion','longue','forfait','journalier'],
  'ami15':      ['perfusion','longue','cancer','immunodeprime'],
  'ami9':       ['perfusion','courte','surveillance','continue'],
  'ami10':      ['perfusion','courte','cancer','immunodeprime'],
  'ami5':       ['retrait','definitif','picc','midline','chambre'],
  'ami4':       ['pansement','complexe','escarre','ulcere','lourd'],
  'bsa':        ['dependance','legere','bsi'],
  'bsb':        ['dependance','intermediaire','bsi'],
  'bsc':        ['dependance','lourde','grabataire','bsi'],
};
function expand(tokens) {
  const out = new Set(tokens);
  for (const t of tokens) {
    const syns = SYNONYMS[t];
    if (syns) for (const s of syns) out.add(s);
  }
  return Array.from(out);
}

// ─── PRÉ-CALCUL BM25 INDEX (lazy singleton) ──────────────
let BM25_INDEX = null;
function buildBM25Index() {
  const docs = CHUNKS.map(c => {
    const toks = tokenize(c.text).map(lightStem);
    return { toks, len: toks.length };
  });
  const N_DOCS = docs.length;
  const avgdl = docs.reduce((s, d) => s + d.len, 0) / Math.max(1, N_DOCS);
  // df per term
  const df = {};
  for (const d of docs) {
    const seen = new Set();
    for (const t of d.toks) if (!seen.has(t)) { seen.add(t); df[t] = (df[t] || 0) + 1; }
  }
  const idf = {};
  for (const t in df) {
    // BM25+ / Robertson-Spärck Jones IDF avec lissage +1 pour éviter les négatifs
    idf[t] = Math.log(1 + (N_DOCS - df[t] + 0.5) / (df[t] + 0.5));
  }
  // tf per doc per term
  const tf = docs.map(d => {
    const m = {};
    for (const t of d.toks) m[t] = (m[t] || 0) + 1;
    return m;
  });
  return { docs, N: N_DOCS, avgdl, idf, tf };
}
function bm25Score(queryTerms, idx) {
  if (!BM25_INDEX) BM25_INDEX = buildBM25Index();
  const k1 = 1.5, b = 0.75;
  const { tf, docs, avgdl, idf } = BM25_INDEX;
  const tfd = tf[idx];
  const dl = docs[idx].len;
  let s = 0;
  for (const q of queryTerms) {
    const f = tfd[q] || 0;
    if (f === 0) continue;
    const numer = f * (k1 + 1);
    const denom = f + k1 * (1 - b + b * dl / avgdl);
    s += (idf[q] || 0) * (numer / denom);
  }
  return s;
}

// ─── COSINE DENSE (vecteurs index déjà normalisés) ───────
function cosineAll(queryVec) {
  if (ALL_VECS.length !== N * DIM) return [];
  // Normaliser la query
  let qn = 0;
  for (let i = 0; i < DIM; i++) qn += queryVec[i] * queryVec[i];
  qn = qn > 0 ? 1 / Math.sqrt(qn) : 0;
  const scores = new Array(N);
  for (let i = 0; i < N; i++) {
    const off = i * DIM;
    let s = 0;
    for (let j = 0; j < DIM; j++) s += queryVec[j] * ALL_VECS[off + j];
    scores[i] = s * qn; // cosinus
  }
  return scores;
}

// ─── QUERY EMBEDDING via HF Inference API ───────────────
async function embedQuery(text) {
  if (!text || text.length < 3) return null;
  try {
    const ctrl = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), 4500);
    const headers = { 'Content-Type': 'application/json' };
    if (HF_TOKEN) headers['Authorization'] = 'Bearer ' + HF_TOKEN;
    const res = await fetch(EMBED_ENDPOINT, {
      method: 'POST',
      headers,
      body: JSON.stringify({ inputs: text, options: { wait_for_model: true } }),
      signal: ctrl.signal,
    });
    clearTimeout(timer);
    if (!res.ok) return null;
    const v = await res.json();
    // HF renvoie parfois [vec] ou vec selon config
    const vec = Array.isArray(v) && typeof v[0] === 'number' ? v
             : Array.isArray(v) && Array.isArray(v[0]) ? v[0]
             : null;
    if (!vec || vec.length !== DIM) return null;
    return new Float32Array(vec);
  } catch (e) {
    return null;
  }
}

// ─── RECIPROCAL RANK FUSION ──────────────────────────────
function rrf(rankings, k) {
  const acc = new Map();
  for (const ranking of rankings) {
    ranking.forEach((idx, rank) => {
      acc.set(idx, (acc.get(idx) || 0) + 1 / (k + rank + 1));
    });
  }
  return Array.from(acc.entries())
    .map(([idx, s]) => ({ idx, score: s }))
    .sort((a, b) => b.score - a.score);
}

// ─── MAIN ────────────────────────────────────────────────
const tokens = expand(tokenize(rawQuery).map(lightStem));

// BM25
const bm25Scored = [];
for (let i = 0; i < N; i++) {
  const s = bm25Score(tokens, i);
  if (s > 0) bm25Scored.push({ idx: i, score: s });
}
bm25Scored.sort((a, b) => b.score - a.score);
const bm25TopIdx = bm25Scored.slice(0, TOP_K_BM25).map(x => x.idx);

// Dense
let denseTopIdx = [];
let ragMode = 'bm25_only';
const qvec = await embedQuery(rawQuery);
if (qvec) {
  const scores = cosineAll(qvec);
  if (scores.length === N) {
    const idxScored = scores.map((s, i) => ({ idx: i, score: s })).sort((a, b) => b.score - a.score);
    denseTopIdx = idxScored.slice(0, TOP_K_DENSE).map(x => x.idx);
    ragMode = 'hybrid_bm25_dense_rrf';
  }
}

// Fusion
let finalRanked;
if (denseTopIdx.length > 0 && bm25TopIdx.length > 0) {
  finalRanked = rrf([bm25TopIdx, denseTopIdx], RRF_K);
} else if (denseTopIdx.length > 0) {
  finalRanked = denseTopIdx.map((idx, rank) => ({ idx, score: 1 / (rank + 1) }));
  ragMode = 'dense_only';
} else {
  finalRanked = bm25Scored;
  ragMode = bm25Scored.length > 0 ? 'bm25_only' : 'empty_fallback';
}

// Top K final
let topFinal = finalRanked.slice(0, TOP_K_FINAL);

// Fallback de sécurité : si vide, retourner les chunks essentiels
if (topFinal.length === 0) {
  const essentialIds = ['ngap_tarif_ami','ngap_regle_principal','ngap_tarif_ifd'];
  topFinal = CHUNKS
    .map((c, i) => ({ idx: i, score: 0.1, id: c.id }))
    .filter(x => essentialIds.includes(CHUNKS[x.idx].id));
  ragMode = 'empty_essentials_fallback';
}

// Assembler rag_chunks (structuré) + ragContext (string pour le prompt)
const rag_chunks = topFinal.map(({ idx, score }) => ({
  id: CHUNKS[idx].id,
  text: CHUNKS[idx].text,
  score: Math.round(score * 10000) / 10000,
}));
const ragContext = rag_chunks
  .map(c => `[${c.id}] ${c.text}`)
  .join('\n');

// Versioning
function hashStr(str) {
  let h = 5381;
  for (let i = 0; i < str.length; i++) { h = ((h << 5) + h) ^ str.charCodeAt(i); h = h >>> 0; }
  return h.toString(16).padStart(8, '0');
}
const corpusText = CHUNKS.map(c => c.text).join('||');
const rulesetHash = hashStr(corpusText);
const rulesetVersion = 'NGAP_2026.3_CIR9_2025_HYBRID_V1';

return [{
  json: {
    ...body,
    rag_chunks,
    ragContext,
    rulesetHash,
