const data = $input.first().json;
let actes = JSON.parse(JSON.stringify(data.actes || []));
let alerts = [...(data.alerts || [])];

function normCode(c) {
  if (!c) return '';
  let s = String(c).toUpperCase().trim().replace(/,/g, '.').replace(/\s+/g, '');
  if (s === 'AMI4.1') s = 'AMI4_1';
  if (s === 'AMX4.1') s = 'AMX4_1';
  return s;
}

const isMaj = (c) => ['IFD','IFI','IK','MCI','MIE','MAU','NUIT','NUIT_PROF','DIM'].includes(normCode(c));
const isBSI = (c) => ['BSA','BSB','BSC'].includes(normCode(c));
const isPerfForfait = (c) => ['AMI9','AMX9','AMI10','AMX10','AMI14','AMX14','AMI15','AMX15','AMI4_1','AMX4_1'].includes(normCode(c));

// ─── RÈGLE 1 : Coefficient — principal(100%) + secondaires(50%) + majorations(100%) ─
// Les forfaits perfusion et BSI restent toujours à 100% (dérogation)
let principalFound = false;
actes = actes.map(a => {
  const c = normCode(a.code);
  if (isMaj(c) || isBSI(c) || isPerfForfait(c)) return { ...a, coefficient: 1 };
  if (!principalFound) { principalFound = true; return { ...a, coefficient: 1 }; }
  return { ...a, coefficient: 0.5 };
});

// ─── RÈGLE 2 : AIS + BSI interdit ─
if (actes.some(a => normCode(a.code).startsWith('AIS')) && actes.some(a => isBSI(a.code))) {
  alerts.push('❌ [V1] AIS + BSI interdit → AIS supprimé');
  actes = actes.filter(a => !normCode(a.code).startsWith('AIS'));
}

// ─── RÈGLE 3 : BSI exclusifs entre eux ─
const bsActs = actes.filter(a => isBSI(a.code));
if (bsActs.length > 1) {
  const order = { BSA:1, BSB:2, BSC:3 };
  const best = [...bsActs].sort((a,b) => order[normCode(b.code)] - order[normCode(a.code)])[0];
  alerts.push('❌ [V1] Plusieurs BSI → conservation du plus élevé');
  actes = actes.filter(a => !isBSI(a.code));
  actes.unshift(best);
}

// ─── RÈGLE 4 : IFD/IFI unique par passage ─
let ifdCount = 0;
actes = actes.filter(a => {
  const c = normCode(a.code);
  if (c === 'IFD' || c === 'IFI') {
    if (ifdCount++) { alerts.push('❌ [V1] IFD/IFI multiple → réduit à 1'); return false; }
  }
  return true;
});

// ─── RÈGLE 5 : NUIT/NUIT_PROF + DIM non cumulables ─
if (actes.some(a => ['NUIT','NUIT_PROF'].includes(normCode(a.code))) && actes.some(a => normCode(a.code) === 'DIM')) {
  alerts.push('❌ [V1] Nuit + dimanche interdit → dimanche supprimé');
  actes = actes.filter(a => normCode(a.code) !== 'DIM');
}

// ─── RÈGLE 6 : NUIT + NUIT_PROF non cumulables (garder NUIT_PROF) ─
if (actes.some(a => normCode(a.code) === 'NUIT') && actes.some(a => normCode(a.code) === 'NUIT_PROF')) {
  alerts.push('❌ [V1] NUIT + NUIT_PROF → NUIT supprimé');
  actes = actes.filter(a => normCode(a.code) !== 'NUIT');
}

// ─── RÈGLE 7 : IK sans distance ─
