  actes = actes.filter(a => !['AMI14','AMX14'].includes(normCode(a.code)));
}

// ─── RÈGLE 9 : MCI non cumulable avec BSI/AMX/IFI ─
const hasBSI  = actes.some(a => isBSI(a.code));
const hasAMX  = actes.some(a => normCode(a.code).startsWith('AMX'));
const hasIFI  = actes.some(a => normCode(a.code) === 'IFI');
if ((hasBSI || hasAMX || hasIFI) && actes.some(a => normCode(a.code) === 'MCI')) {
