const data    = $input.first().json;
const actes   = data.actes || [];
const historique = data.historique || [];
const just    = data.justification || {};
const pattern = data.patient_pattern || {};
const preuve  = data.preuve_soin || {};
const ctx     = data.nlp_contexte || {};
const texte   = (data.texte || '').toLowerCase();

function normCode(c) {
  if (!c) return '';
  let s = String(c).toUpperCase().trim().replace(/,/g, '.').replace(/\s+/g, '');
  if (s === 'AMI4.1') s = 'AMI4_1';
  if (s === 'AMX4.1') s = 'AMX4_1';
  return s;
}

let controle = { anomalies: [], niveau: 'OK', decision: 'ACCEPTÉ' };

actes.forEach(a => {
  const code = normCode(a.code);
  if (code==='BSC' && !just.dependance_lourde) controle.anomalies.push('BSC sans dépendance lourde documentée');
  if (code==='BSB' && !just.dependance)        controle.anomalies.push('BSB sans dépendance documentée');
  if (a.nom?.toLowerCase().includes('complexe') && !just.plaie_complexe) controle.anomalies.push('Acte complexe sans justification clinique');
  if (code==='MCI' && !just.plaie && !ctx.palliatif) controle.anomalies.push('MCI sans contexte soin complexe ou palliatif');
  if (code==='AMI5' && !texte.match(/retrait|d[eé]branchement\s+d[eé]finiti|fin\s+de\s+(traitement|chimio)/)) controle.anomalies.push('AMI5 sans contexte retrait définitif dispositif');
});

// IFD/IFI sans domicile
if (actes.some(a => ['IFD','IFI'].includes(normCode(a.code))) && !just.domicile) controle.anomalies.push('IFD/IFI sans preuve domicile');

// Distance sans domicile
const distKm = parseFloat(data.distance_km)||0;
if (distKm>0 && !just.domicile) controle.anomalies.push('Distance documentée sans mention domicile');

// Schéma répétitif
if (historique.length > 5) {
  const actesStr = JSON.stringify(actes.map(a => normCode(a.code)).sort());
  const same = historique.filter(h => { try { return JSON.stringify((h.actes||[]).map(a => normCode(a.code)).sort()) === actesStr; } catch(e) { return false; } });
  if (same.length >= 3) controle.anomalies.push('Schéma répétitif (×'+same.length+')');
}

// Pattern patient
if (pattern.flags && pattern.flags.length > 0) {
  pattern.flags.forEach(f => controle.anomalies.push('[PATTERN] '+f.replace(/^[🚨⚠️✅ℹ️]+\s*/,'').substring(0,80)));
}
if (pattern.evolution_dependance === 'STATIQUE') controle.anomalies.push('Dépendance statique — absence d\'évolution clinique');

// Montants
if (data.total > 80) controle.anomalies.push('Montant très élevé (> 80 €)');

// Score fraude
if (data.fraud?.level === 'HIGH') controle.anomalies.push('Score fraude élevé ('+data.fraud.score+' pts)');

// ─── CIR-9/2025 — AMI14/15 ──────────────────────────────
const hasAMI14 = actes.some(a => ['AMI14','AMX14'].includes(normCode(a.code)));
const hasAMI15 = actes.some(a => ['AMI15','AMX15'].includes(normCode(a.code)));
if (hasAMI14 && hasAMI15) controle.anomalies.push('CIR-9/2025 violée : AMI14 + AMI15 même jour interdit');

// 2e forfait AMI14/15 dans historique même jour
if (historique.length > 0 && (hasAMI14 || hasAMI15)) {
  const dateSoin = (data.date_soin || '').slice(0, 10);
  if (dateSoin) {
    const sameDayPerf = historique.filter(h => {
      if ((h.date_soin || '').slice(0, 10) !== dateSoin) return false;
      return (h.actes || []).some(a => ['AMI14','AMX14','AMI15','AMX15'].includes(normCode(a.code)));
    });
    if (sameDayPerf.length > 0) controle.anomalies.push('CIR-9/2025 : 2e forfait perfusion longue sur même jour (déjà AMI14/15 ce jour-là)');
  }
}

// MCI + BSI
if (actes.some(a => ['BSA','BSB','BSC'].includes(normCode(a.code))) && actes.some(a => normCode(a.code) === 'MCI')) {
  controle.anomalies.push('MCI + BSI interdit (règle NGAP)');
}

// ─── Preuve soin ────────────────────────────────────────
if (preuve.force_probante === 'ABSENTE') {
  controle.anomalies.push('Aucune preuve terrain — absence d\'élément justificatif opposable');
} else if (preuve.force_probante === 'FORTE') {
  if (controle.anomalies.length > 0) controle.anomalies.pop();
  controle.anomalies.push('[DÉFENSE] Preuve forte présente : '+preuve.type);
}

// ─── Niveau ─────────────────────────────────────────────
if (controle.anomalies.length >= 4) { controle.niveau='CRITIQUE'; controle.decision='REJET + CONVOCATION CONTRÔLE'; }
else if (controle.anomalies.length >= 2) { controle.niveau='SURVEILLANCE'; controle.decision='ACCEPTÉ AVEC MISE EN SURVEILLANCE'; }
else if (controle.anomalies.length >= 1) { controle.niveau='VIGILANCE'; controle.decision='ACCEPTÉ AVEC VIGILANCE'; }

return [{ json: { ...data, cpam_simulation: controle } }];

// ======================================================
// SCORING INFIRMIÈRE v4
// NOUVEAU v7 : preuve_soin dans scoring
// ======================================================
const data = $input.first().json;
const historique = data.historique || [];
const pattern    = data.patient_pattern || {};
const preuve     = data.preuve_soin || {};

let score = 0;
let metrics = { total_actes:historique.length, bsi_rate:0, nuit_rate:0, montant_moyen:0, anomalies:0, preuve_strength: preuve.force_probante || 'ABSENTE' };

if (historique.length > 0) {
  const bsiCount  = historique.filter(h=>h.actes?.some(a=>['BSA','BSB','BSC'].includes(a.code))).length;
  const nuitCount = historique.filter(h=>h.actes?.some(a=>['NUIT','NUIT_PROF'].includes(a.code))).length;
  const totalMoy  = historique.reduce((s,h)=>s+(parseFloat(h.total)||0),0)/historique.length;
  metrics.bsi_rate      = Math.round(bsiCount /historique.length*100)/100;
  metrics.nuit_rate     = Math.round(nuitCount/historique.length*100)/100;
  metrics.montant_moyen = Math.round(totalMoy*100)/100;
  if (metrics.bsi_rate  > 0.5)  { score+=3; metrics.anomalies++; }
  if (metrics.nuit_rate > 0.3)  { score+=2; metrics.anomalies++; }
  if (metrics.montant_moyen > 35) { score+=2; }
}

if (data.fraud?.level === 'HIGH')   { score+=5; metrics.anomalies++; }
if (data.fraud?.level === 'MEDIUM') { score+=2; }
if (data.cpam_simulation?.niveau === 'CRITIQUE') { score+=4; metrics.anomalies++; }
if (pattern.evolution_dependance === 'STATIQUE') { score+=3; metrics.anomalies++; }
if (pattern.repetition_score >= 7)               { score+=4; metrics.anomalies++; }
if (!pattern.coherence_pathologie)               { score+=2; }

// NOUVEAU v7 : impact preuve_soin sur le scoring IDE
if (preuve.force_probante === 'ABSENTE')  { score+=3; metrics.anomalies++; }
if (preuve.force_probante === 'FORTE')    { score = Math.max(0, score-2); }

let level = 'SAFE';
if (score >= 7) level = 'DANGER';
else if (score >= 3) level = 'SURVEILLANCE';

return [{ json: { ...data, infirmiere_scoring: { score, level, metrics } } }];

// ======================================================
// BLOCAGE FSE — HIGH + MEDIUM/CRITIQUE
// ======================================================
const data = $input.first().json;
const fraudLevel = data.fraud?.level || 'LOW';
const cpamNiveau = data.cpam_simulation?.niveau || 'OK';

const blocked = fraudLevel === 'HIGH' || (fraudLevel === 'MEDIUM' && cpamNiveau === 'CRITIQUE');

if (blocked) {
  return [{ json: {
    ok: false, blocked: true, error: 'CPAM_BLOCK',
    message: 'Cotation bloquée — validation humaine obligatoire avant envoi FSE',
    reason: fraudLevel === 'HIGH' ? 'Fraude score élevé ('+data.fraud.score+' pts)' : 'Fraude MEDIUM + CPAM CRITIQUE',
    fraud: data.fraud, cpam_simulation: data.cpam_simulation,
    infirmiere_scoring: data.infirmiere_scoring || null,
    patient_pattern:    data.patient_pattern    || null,
    preuve_soin:        data.preuve_soin        || null,
    actes: data.actes, total: data.total,
    alerts: data.alerts || [], justification: data.justification || {},
    audit: data.audit || null
  }}];
}

return [{ json: data }];

// ======================================================
// FSE GENERATOR v6 — FINAL BOUCLIER ANTI-REDRESSEMENT
// NOUVEAU v7 : preuve_soin dans FSE + audit complet
// ======================================================
const data = $input.first().json;
if (data.blocked) return [{ json: data }];

const actes = (data.actes || []).map(a => ({ code:a.code, nom:a.nom||'', base:a.base||0, coefficient:a.coefficient, montant:a.total }));
const preuve = data.preuve_soin || {};

const fse = {
  version:      'FSE-1.40',
  date:         new Date().toISOString(),
  ngap_version: data.ngap_version || '2026.1',
  patient: {
    id:  data._ddn || data.patient_id || 'UNKNOWN',
    ald: data._exo==='1' || data._exo?.toLowerCase()==='ald',
    ddn: data._ddn || ''
  },
  praticien: {
    infirmiere: data._infirmiere||'', rpps: data.rpps||data._rpps||'',
    adeli: data.adeli||data._adeli||'', structure: data.structure||''
  },
  prescripteur: { nom:data._prescripteur_nom||'', rpps:data._prescripteur_rpps||'', date:data._date_prescription||'' },
  facturation: {
    actes, total:data.total, amo_amount:data.amo_amount, amc_amount:data.amc_amount,
    part_patient:data.part_patient, taux_amo:data.taux_amo, dre_requise:data.dre_requise
  },
  teletransmission: { mode:data._regl||'SESAM_VITALE', dre:data.dre_requise },
  // JUSTIFICATION MÉDICALE HORODATÉE (v6)
  justification_medicale: {
    dependance:          data.justification?.dependance        || false,
    dependance_lourde:   data.justification?.dependance_lourde || false,
    plaie:               data.justification?.plaie             || false,
    plaie_complexe:      data.justification?.plaie_complexe    || false,
    domicile:            data.justification?.domicile          || false,
    enfant:              data.justification?.enfant            || false,
    nuit_horaire:        data.justification?.nuit_horaire      || false,
    ald:                 data.justification?.ald               || false,
    prescription:        data.justification?.prescription      || false,
    distance_km:         data.distance_km || 0,
    timestamp:           data.justification?.timestamp         || new Date().toISOString(),
    source:              data.justification?.source            || 'NLP_V6_AMI',
    texte_original_hash: data.justification?.texte_original_hash || ''
  },
  // PREUVE SOIN — NOUVEAU v7 : bouclier anti-redressement
  // Prouve que le soin a réellement été réalisé comme décrit
  // La photo / signature n'est JAMAIS transmise — uniquement son hash
  preuve_soin: {
    type:              preuve.type              || 'auto_declaration',
    timestamp:         preuve.timestamp         || new Date().toISOString(),
    hash_preuve:       preuve.hash_preuve       || '',
    certifie_ide:      preuve.certifie_ide      ?? true,
    signature_patient: preuve.signature_patient || false,
    photo_presente:    preuve.photo_presente    || false,
    geo_zone:          preuve.geo_zone          || '',
    force_probante:    preuve.force_probante    || 'STANDARD'
  },
  qualite: {
    alerts: data.alerts||[], optimisations:data.optimisations||[],
    suggestions: data.suggestions_optimisation||[],
    fraud_level: data.fraud?.level||'LOW', fraud_score:data.fraud?.score||0,
    fraud_flags: data.fraud?.flags||[],
    cpam_simulation:    data.cpam_simulation    || null,
    infirmiere_scoring: data.infirmiere_scoring || null,
    patient_pattern:    data.patient_pattern    || null
  },
  audit: {
    ...(data.audit || {}),
    ruleset_hash:    data.rulesetHash    || data.audit?.ruleset_hash    || '',
    ruleset_version: data.rulesetVersion || data.audit?.ruleset_version || 'NGAP_2026.1_FULL'
  }
};

return [{ json: { ...data, fse, scor_ready: true } }];

// Fusion réponse finale — v13 ANTI-LOG-POLLUTION
// Objectif : ne JAMAIS renvoyer { ok:false, total:0, actes:[] } qui déclenche
// le warn "Réponse n8n vide → fallback" côté worker.
// → Renvoie toujours ok:true + flag _ai_failed/_empty_input pour traçabilité.
const safeNum = (v) => isFinite(parseFloat(v)) ? Math.round(parseFloat(v)*100)/100 : 0;

// 1. Source primaire : FSE Generator (chaîne complète)
let parsed = {};
let source = 'fse';
try { parsed = $('FSE Generator').first()?.json || {}; } catch(e) { parsed = {}; }

// 2. Fallback source : Parser résultat IA (si FSE n'a pas tourné)
if (!parsed || Object.keys(parsed).length === 0 || (!parsed.ok && !parsed.actes && !parsed.total)) {
  try {
    const fromParser = $('Parser résultat IA').first()?.json;
    if (fromParser && (fromParser.actes || fromParser.total !== undefined)) {
      parsed = fromParser;
      source = 'parser';
    }
  } catch(e) { /* parser non accessible */ }
}

// 3. Lire le webhook input pour récupérer le contexte
let webhookInput = {};
try { webhookInput = $('Webhook').first()?.json?.body || $('Webhook').first()?.json || {}; } catch(e) {}
const inputTexte = String(webhookInput.texte || '').trim();
const inputTrivial = inputTexte.length < 5;

// 4. Données BDD optionnelles
let savedId = null, savedAt = null, savedInvoice = null;
try {
  const saved = $('Sauvegarder en BDD').first()?.json;
  if (saved && !saved.error) {
    savedId      = saved?.id             || null;
    savedAt      = saved?.created_at     || null;
    savedInvoice = saved?.invoice_number || null;
  }
} catch(e) { /* Branche BDD non exécutée — normal en mode admin/skip_db */ }

// 5. Cas blocked (FraudGuard, etc.) → propager tel quel
if (parsed && parsed.blocked) {
  return [{ json: { ...parsed, cotation_id: null, saved_at: null } }];
}

// 6. Cas réponse VIDE → renvoyer ok:true + _ai_failed (pas ok:false)
//    Le worker reconnaît _ai_failed/_empty_input et logue en info (pas warn)
const isEmpty = !parsed
  || Object.keys(parsed).length === 0
  || (safeNum(parsed.total) === 0 && (!Array.isArray(parsed.actes) || parsed.actes.length === 0));

if (isEmpty) {
  return [{ json: {
    ok: true,                     // ← change : toujours true (évite ok:false côté worker)
    _ai_failed: !inputTrivial,    // flag tracé : IA a échoué (texte non trivial)
    _empty_input: inputTrivial,   // flag tracé : input utilisateur trivial
    _source: source,
    actes: [], total: 0,
    amo_amount: 0, amc_amount: 0,
    part_amo: 0, part_amc: 0, part_patient: 0,
    taux_amo: 0.6, dre_requise: false,
    horaire_type: 'jour',
    alerts: inputTrivial
      ? ['Texte de soin trop court — précisez les actes effectués.']
      : ['Estimation IA indisponible — calcul local recommandé.'],
    optimisations: [], suggestions_optimisation: [],
    fraud: { score: 0, level: 'LOW', flags: [] },
    cpam_simulation: null, infirmiere_scoring: null,
    patient_pattern: null, preuve_soin: null,
    justification: {}, fse: null,
    invoice_number: savedInvoice || null,
    cotation_id: savedId, saved_at: savedAt,
    db_invoice_number: savedInvoice,
    ngap_version: '2026.1'
  }}];
}

// 7. Cas nominal — réponse complète
return [{ json: {
  ok:                       true,
  actes:                    Array.isArray(parsed.actes) ? parsed.actes : [],
  total:                    safeNum(parsed.total),
  amo_amount:               safeNum(parsed.amo_amount),
  amc_amount:               safeNum(parsed.amc_amount),
  part_amo:                 safeNum(parsed.part_amo),
  part_amc:                 safeNum(parsed.part_amc),
  part_patient:             safeNum(parsed.part_patient),
  taux_amo:                 safeNum(parsed.taux_amo) || 0.6,
  dre_requise:              !!parsed.dre_requise,
  horaire_type:             parsed.horaire_type || 'jour',
  alerts:                   Array.isArray(parsed.alerts) ? parsed.alerts : [],
  optimisations:            Array.isArray(parsed.optimisations) ? parsed.optimisations : [],
  suggestions_optimisation: parsed.suggestions_optimisation || [],
  justification:            parsed.justification || {},
  preuve_soin:              parsed.preuve_soin || null,
  fraud:                    parsed.fraud || { score: 0, level: 'LOW', flags: [] },
  cpam_simulation:          parsed.cpam_simulation || null,
  infirmiere_scoring:       parsed.infirmiere_scoring || null,
  patient_pattern:          parsed.patient_pattern || null,
  fse:                      parsed.fse || null,
  scor_ready:               !!parsed.scor_ready,
  audit:                    parsed.audit || null,
  ngap_version:             parsed.ngap_version || '2026.1',
  invoice_number:           savedInvoice || parsed.invoice_number || null,
  cotation_id:              savedId,
  saved_at:                 savedAt,
  db_invoice_number:        savedInvoice
}}];

const items = $input.all();
const rows = items.map(i=>i.json).filter(r=>r && typeof r==='object' && !r.error);
return [{ json: { ok:true, data:rows, count:rows.length } }];

const body = $('Webhook Supprimer').item.json;
const deleteOne = !!(body.id && !body.patient_id);
return [{ json: { ...body, _delete_one: deleteOne } }];

