// ============================================================
// SPLIT BY IDE v1.0 — Mode Cabinet
// Reçoit un payload avec actes déjà filtrés par IDE (depuis le worker)
// Prépare le payload pour le pipeline NGAP solo existant
// ============================================================
const body = $input.first().json;

// Le worker a déjà splitté les actes par IDE avant d'appeler N8N
// On reçoit donc un payload mono-IDE avec _cabinet_mode=true
// On le passe tel quel au pipeline NLP → pipeline solo existant

// Enrichissement cabinet : ajouter flag pour la réponse finale
return [{ json: {
  ...body,
  _cabinet_mode:      true,
  _parent_user:       body._parent_user || body.infirmiere_id || '',
  _cabinet_ide_label: body.infirmiere_id || 'IDE_inconnu',
  // S'assurer que le texte est disponible pour le NLP
  texte:              body.texte || JSON.stringify(body.actes || []),
} }];

// ============================================================
// MERGE CABINET v1.0
// Reçoit les résultats du pipeline solo (1 item = 1 résultat IDE)
// En mode solo : laisse passer sans modification
// En mode cabinet : ajoute le flag cabinet_mode pour info
// Note : le vrai merge multi-IDE est fait côté worker en parallèle.
// Ce node sert uniquement à transiter proprement.
// ============================================================
const data = $input.first().json;

// Mode cabinet : enrichir la réponse avec l'id de l'IDE
if (data._cabinet_mode) {
  const ideId = data._cabinet_ide_label || data.infirmiere_id || 'IDE';
  return [{ json: {
    ...data,
    ide_id:       ideId,
    cabinet_mode: true,
    // Nettoyer les champs internes avant renvoi
    _cabinet_mode:       undefined,
    _cabinet_ide_label:  undefined,
    _parent_user:        undefined,
  } }];
}

// Mode solo : passer tel quel
return [{ json: data }];

// ============================================================
// ROUTEUR PRINCIPAL — détecte le type de requête
// ============================================================
const body = $input.first().json?.body || $input.first().json || {};
const path = $input.first().json?.path || '';

// Détecter le type
const isRLTrain     = !!body.episodes;
const isForecastUpd = !!body.zone && body.actual_count !== undefined;
const isForecastQry = !!body.zones || !!body.zone;

return [{ json: {
  ...body,
  _type: isRLTrain ? 'rl_train' : isForecastUpd ? 'forecast_update' : 'forecast_query',
  _received_at: new Date().toISOString(),
} }];

// ============================================================
// RL TRAINER — Q-Learning offline sur les épisodes reçus
// ============================================================
// Constantes RL
const RL_ALPHA  = 0.1;
const RL_GAMMA  = 0.9;
const RL_ACTIONS = [
  'assign_high_revenue',
  'assign_nearest',
  'assign_low_fatigue',
  'delay_patient',
  'insert_break',
  'swap_patients',
];

const data     = $input.first().json;
const episodes = data.episodes || [];

// Q-table initiale vide (N8N est stateless — on retourne la Q-table mise à jour
// que le client peut re-fusionner avec sa version locale)
let qtable = data.qtable || {};

function stateKey({ revenueHour=0, fatigueAvg=0, pendingCount=0, timeOfDay=0, surgeLevel=0 }) {
  const r = Math.min(3, Math.floor(revenueHour / 20));
  const f = Math.min(2, Math.floor(fatigueAvg  / 0.4));
  const p = Math.min(3, Math.floor(pendingCount / 5));
  const t = Math.min(3, Math.floor(timeOfDay   / 360));
  const s = Math.min(2, Math.floor(surgeLevel));
  return `r${r}_f${f}_p${p}_t${t}_s${s}`;
}

function getQ(qt, sk, action) { return (qt[sk] || {})[action] || 0; }
function setQ(qt, sk, action, val) {
  if (!qt[sk]) qt[sk] = {};
  qt[sk][action] = val;
}

let nbUpdates = 0;
const stats = { episodes: episodes.length, transitions: 0, states_seen: new Set() };

for (const ep of episodes) {
  const { states=[], actions=[], rewards=[] } = ep;
  for (let i = 0; i < actions.length; i++) {
    const state     = states[i]   || {};
    const action    = actions[i]  || RL_ACTIONS[0];
    const reward    = rewards[i]  || 0;
    const nextState = states[i+1] || state;

    const sk  = stateKey(state);
    const nsk = stateKey(nextState);
    stats.states_seen.add(sk);

    // Valeur max état suivant
    const maxNextQ = Math.max(...RL_ACTIONS.map(a => getQ(qtable, nsk, a)));

    // Bellman update
    const current = getQ(qtable, sk, action);
    const updated = current + RL_ALPHA * (reward + RL_GAMMA * maxNextQ - current);
    setQ(qtable, sk, action, Math.round(updated * 10000) / 10000);

    nbUpdates++;
    stats.transitions++;
  }
}

// Extraire les meilleures actions par état pour le résumé
const policy = {};
for (const [sk, actions] of Object.entries(qtable)) {
  let best = RL_ACTIONS[0], bestQ = -Infinity;
  for (const [a, q] of Object.entries(actions)) {
    if (q > bestQ) { bestQ = q; best = a; }
  }
  policy[sk] = { best_action: best, q_value: bestQ };
}

return [{ json: {
  success:     true,
  nb_updates:  nbUpdates,
  states_seen: stats.states_seen.size,
  episodes:    stats.episodes,
  transitions: stats.transitions,
  qtable_diff: qtable,  // à merger côté client
  policy_summary: Object.entries(policy).slice(0, 20).map(([sk, v]) => ({ state: sk, ...v })),
  trained_at:  new Date().toISOString(),
} }];

// ============================================================
// FORECAST UPDATE — mise à jour modèle de prévision demande
// Reçoit : { zone, actual_count, date, user_id }
// Stocke en BDD pour agrégation multi-utilisateurs
// ============================================================
const data = $input.first().json;
const zone  = data.zone  || 'unknown';
const count = parseInt(data.actual_count || 0);
const date  = data.date  || new Date().toISOString().slice(0, 10);
const dow   = new Date(date).getDay();
const month = new Date(date).getMonth() + 1;

// Facteurs saisonnalité
const DAY_FACTORS   = [0.55, 1.10, 1.05, 1.10, 1.05, 0.90, 0.60];
const MONTH_FACTORS = [1.05, 0.95, 1.00, 0.95, 1.00, 0.95, 0.80, 0.75, 1.00, 1.10, 1.10, 1.15];

// Dé-saisonnaliser pour obtenir la base
const dayF   = DAY_FACTORS[(dow + 6) % 7]   || 1.0;
const monthF = MONTH_FACTORS[month - 1]       || 1.0;
const base   = count / (dayF * monthF);

return [{ json: {
  zone,
  date,
  actual_count:   count,
  deseasonalized: Math.round(base * 100) / 100,
  dow,
  month,
  day_factor:     dayF,
  month_factor:   monthF,
  _ready_for_db:  true,
} }];

// ============================================================
// FORECAST QUERY — calcule la prévision demande pour zones/date
// Reçoit : { zones: ['Quimper', 'Brest'], date: '2026-04-19' }
// Retourne prévisions + recommandations
// ============================================================
const data  = $input.first().json;
const zones = data.zones || (data.zone ? [data.zone] : []);
const date  = new Date(data.date || Date.now() + 86400000);

const DAY_FACTORS   = [0.55, 1.10, 1.05, 1.10, 1.05, 0.90, 0.60];
const MONTH_FACTORS = [1.05, 0.95, 1.00, 0.95, 1.00, 0.95, 0.80, 0.75, 1.00, 1.10, 1.10, 1.15];
const DEFAULT_BASE  = 8;

// Bases depuis BDD (si disponibles via node précédent)
const dbBases = {};
const dbResults = $('Requête Forecast BDD')?.all() || [];
for (const row of dbResults) {
  const r = row.json;
  if (r.zone && r.avg_base) dbBases[r.zone] = parseFloat(r.avg_base);
}

const dow   = (date.getDay() + 6) % 7;
const month = date.getMonth() + 1;
const dayF  = DAY_FACTORS[dow]      || 1.0;
const monF  = MONTH_FACTORS[month-1] || 1.0;

const forecasts = zones.map(zone => {
  const base     = dbBases[zone] || DEFAULT_BASE;
  const pred     = Math.round(Math.max(1, base * dayF * monF));
  const threshold = (dbBases[zone] || DEFAULT_BASE) * 1.3;
  const high     = pred > threshold;
  return {
    zone,
    predicted:       pred,
    base_avg:        Math.round(base * 100) / 100,
    trend:           high ? '↑ forte demande' : '→ normal',
    high_demand:     high,
    recommendation:  high
      ? `+1 IDE recommandé sur ${zone} (${pred} patients prévus)`
      : `Charge normale sur ${zone}`,
    confidence:      dbBases[zone] ? 'high' : 'low',
  };
}).sort((a, b) => b.predicted - a.predicted);

const totalPred = forecasts.reduce((s, f) => s + f.predicted, 0);
const highZones = forecasts.filter(f => f.high_demand);

return [{ json: {
  forecasts,
  date:        date.toISOString().slice(0, 10),
  total_predicted: totalPred,
  high_demand_zones: highZones.map(f => f.zone),
  global_recommendation: highZones.length > 0
    ? `Renforcer les zones : ${highZones.map(f => f.zone).join(', ')}`
    : 'Planning normal — aucun renforcement requis',
  computed_at: new Date().toISOString(),
} }];

// ============================================================
// FORMATAGE RÉPONSE RL
// ============================================================
const data = $input.first().json;
return [{ json: {
  status:      'trained',
  nb_updates:  data.nb_updates,
  states_seen: data.states_seen,
  qtable_diff: data.qtable_diff,
  policy_summary: data.policy_summary,
  message:     `Q-Learning: ${data.transitions} transitions, ${data.states_seen} états appris`,
  trained_at:  data.trained_at,
} }];

// ============================================================
// RÉPONSE FORECAST UPDATE
// ============================================================
const db = $input.first().json;
return [{ json: {
  status:  'updated',
  zone:    db.zone,
  new_avg: db.avg_base ? Math.round(parseFloat(db.avg_base) * 100) / 100 : null,
  nb_obs:  db.nb_obs || 1,
  message: `Modèle mis à jour pour zone ${db.zone}`,
} }];

// ============================================================
// RL DECISION LOGGER v1 — AMI v7
// Journalise la décision de cotation pour entraînement RL futur
// Calcule le reward réel = revenue - km_cost - fatigue_cost
// NE modifie PAS la réponse — transparent pour le pipeline
// ============================================================
const data = $input.first().json;

function computeReward({ revenue = 0, km = 0, fatigue = 0, delay = 0 }) {
  return Math.round(
    revenue
    - (km * 0.35)
    - (fatigue * 5)
    - (delay * 2)
  );
}

const revenue   = parseFloat(data.total) || 0;
const km        = parseFloat(data.distance_km) || 0;
const timeSlot  = (data.heure_soin || '').slice(0, 2);
const isNight   = parseInt(timeSlot) >= 20 || parseInt(timeSlot) <= 8;
const nbActes   = Array.isArray(data.actes) ? data.actes.length : 0;
const reward    = computeReward({ revenue, km });

const rlDecision = {
  timestamp:    new Date().toISOString(),
  user_id:      data._user_id || data.infirmiere_id || '',
  invoice:      data.invoice_number || '',
  state: {
    zone:        data.geo_zone || 'unknown',
    time_slot:   isNight ? 'night' : 'day',
    nb_actes:    nbActes,
    load_level:  nbActes > 3 ? 'heavy' : 'normal',
  },
  action:       data.rulesetVersion || 'n8n_v7',
  reward,
  outcome: {
    total:      revenue,
    km,
    nb_actes:   nbActes,
    fallback:   !!data.fallback,
    fraud_score: data.fraud?.score || 0,
  },
};

// Passer les données RL dans la réponse (le Worker les récupère via system_logs)
return [{ json: { ...data, _rl_decision: rlDecision } }];

// ============================================================
// HEATMAP ZONE SCORER v1 — AMI v7
// Enrichit la réponse avec le score de zone géographique
// Utilisé par le front pour afficher la heatmap décisionnelle
// ============================================================
const data = $input.first().json;

// Score de zone simplifié basé sur les patterns temporels et le montant
// Le vrai scoring se fait côté Worker avec les données historiques
const total       = parseFloat(data.total) || 0;
const nbActes     = Array.isArray(data.actes) ? data.actes.length : 0;
const heure       = (data.heure_soin || '').slice(0, 2);
const isRushHour  = parseInt(heure) >= 7 && parseInt(heure) <= 9;
const isNight     = parseInt(heure) >= 20 || parseInt(heure) <= 8;

// Estimation revenue_per_hour (≈ 20 min par acte)
const tempsEstime    = Math.max(nbActes * 20, 10); // minutes
const revenuePerHour = total > 0 ? Math.round(total / tempsEstime * 60 * 100) / 100 : 0;

const zoneData = {
  revenue_per_hour: revenuePerHour,
  km:               parseFloat(data.distance_km) || 0,
  delay_risk:       isRushHour ? 0.5 : isNight ? 0.1 : 0.2,
  geo_zone:         data.geo_zone || '',
  timestamp:        new Date().toISOString(),
};

// Score composite = revenue_per_hour - km_cost - delay_cost
const zoneScore = Math.round(
  revenuePerHour
  - (zoneData.km * 0.35)
  - (zoneData.delay_risk * 5)
);

return [{ json: { ...data, zone_data: zoneData, zone_score: zoneScore } }];
